function rexDetectIntent(text){var lower=low(text);if(contains(lower,["tell me about yourself","introduce yourself","about myself","about yourself"])){return "intro";}if(contains(lower,["weakness","strength","strengths"])){return "strength";}if(contains(lower,["star","competency","behaviour","behavior","example","scenario"])){return "star";}if(contains(lower,["why do you want","why this role","why should","motivation","why are you interested"])){return "motivation";}if(contains(lower,["conflict","difficult","challenge","pressure","prioritise","prioritize","deadline","stakeholder"])){return "behaviour";}if(contains(lower,["improve","rewrite","make this better","polish","word this","reword"])){return "rewrite";}if(contains(lower,["nurse","healthcare","patient","care","clinical","support worker"])){return "healthcare";}if(contains(lower,["data","analyst","excel","power bi","dashboard","report","sql"])){return "data";}return "general";}
