function safeFileName(name){return String(name||"cover_letter.doc").replace(/[\\\/:\*\?\"<>\|]+/g," ").replace(/\s+/g," ").replace(/^\s+|\s+$/g,"");}
function escapeHtmlForDoc(text){return String(text||"").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");}
function isNhsTrustCompany(name){var lower=low(name);return has(lower,"nhs")||has(lower,"foundation trust")||has(lower,"hospital trust")||has(lower,"healthcare trust")||has(lower,"university hospitals");}
function findNhsValues(name){try{if(window.top&&typeof window.top.lookupNhsTrustValues==="function"){return window.top.lookupNhsTrustValues(name);} }catch(e){}return {ok:false,values:[],sourceUrl:""};}
function renderSummary(){hideSummaryBar();}
function chip(label,tone){return '<span class="chip '+tone+'">'+esc(label)+'</span>';}
function lis(arr){var h="";for(var i=0;i<arr.length;i++){h+="<li>"+esc(arr[i])+"</li>";}return h;}
function renderBulletSections(sections){if(!sections||!sections.length){return '<pre class="cv-bullets">No duties generated yet.</pre>';}var h="",i,j,openAttr;for(i=0;i<sections.length;i++){openAttr=i===0?" open":"";h+='<details class="bullet-accordion"'+openAttr+'><summary>'+esc(sections[i].header)+'</summary><ul class="generated-duty-list">';for(j=0;j<sections[i].duties.length;j++){h+='<li>'+esc(sections[i].duties[j])+'</li>';}h+='</ul></details>';}return h;}
function renderResults(){var h="",job=current.length?current[0]:null,mode,selected,wordCount,previewPanel,editorPanel,aiChip="",chooser="",regenDisabled="",regenLabel="Regenerate";if(!el.results){return;}if(!job){el.results.innerHTML="";return;}ensureCoverLetterOptions(job);mode=job.selectedLetterMode||"civil";selected=getSelectedLetter(job);wordCount=countTextWords(selected);previewPanel=renderLetterPreview(job,0,mode,selected);editorPanel=renderAdminLetterEditor(job,0,mode,selected);aiChip=job.aiError?chip("Built-in fallback","warn"):"";chooser=renderCoverLetterOptionChooser(job);if(job.coverLetterOptions&&job.coverLetterOptions.length>=3){regenDisabled=' disabled';regenLabel='3 Options Ready';}h+='<article class="result-card cover-letter-result-card"><div class="result-topline"><div><p class="match-badge">Cover Letter Ready</p><h3 class="job-title">'+esc(job.title)+'</h3><p class="job-meta">'+esc(job.company)+' | Using '+esc(job.profileLabel||"Selected CV")+'</p></div><div class="fit-score">'+wordCount+' words</div></div><div class="chip-row">'+chip("Cover letter","good")+chip(job.profileLabel||"Selected CV","good")+aiChip+(canEditCoverLetters()?chip("Admin editing enabled","good"):"")+'</div><div class="draft-panel"><div class="draft-header"><h4>Cover Letter Preview</h4><div class="letter-controls"><button class="ghost-button regen-letter-btn" type="button" data-i="0"'+regenDisabled+'>'+regenLabel+'</button><button class="primary-button download-selected-letter-btn" type="button" data-i="0">Download Word</button></div></div><p class="job-meta">'+(job.aiGenerated?"This cover letter was generated using your selected CV source and the pasted job description.":"This cover letter was generated from your selected CV source and the pasted job description for this role.")+'</p>'+chooser+previewPanel+editorPanel+'</div></article>';el.results.innerHTML=h;}
function loadHistory(){var raw="";try{raw=window.localStorage?window.localStorage.getItem(historyKey):"";}catch(e){raw="";}if(!raw){return [];}try{return JSON.parse(raw)||[];}catch(err){return [];}}
function persistHistory(){try{if(window.localStorage){window.localStorage.setItem(historyKey,JSON.stringify(currentHistory));}}catch(e){}}
function saveCurrentRun(){var snapshot={createdAt:new Date().toLocaleString(),results:[]},i;for(i=0;i<current.length;i++){snapshot.results.push({title:current[i].title,company:current[i].company,location:current[i].location||"",salary:current[i].salary||"",score:current[i].score||100,reasons:current[i].reasons||[],risks:current[i].risks||[],tailor:current[i].tailor||[],profileLabel:current[i].profileLabel||"Selected CV",nhsLetter:current[i].nhsLetter,civilLetter:current[i].civilLetter,selectedLetterMode:current[i].selectedLetterMode||"civil",letterVariant:current[i].letterVariant||0,raw:current[i].raw,manual:true,website:{ok:false,websites:[]},sponsors:[],nhsValues:current[i].nhsValues||{ok:false,values:[],sourceUrl:""},profileText:current[i].profileText||"",coverLetterOptions:current[i].coverLetterOptions||[],selectedCoverLetterOptionIndex:current[i].selectedCoverLetterOptionIndex||0});}currentHistory.unshift(snapshot);currentHistory=currentHistory.slice(0,12);persistHistory();renderHistory();}
function renderHistory(){if(!el.historyList){return;}if(!currentHistory.length){el.historyList.className="history-list empty-state";el.historyList.innerHTML="No saved cover letter history yet.";return;}el.historyList.className="history-list";var h="",i,top;for(i=0;i<currentHistory.length;i++){top=currentHistory[i].results&&currentHistory[i].results[0]?currentHistory[i].results[0]:null;h+='<div class="history-card"><div class="history-topline"><div class="history-main"><label class="history-check-wrap"><input class="history-check" type="checkbox" data-history-index="'+i+'"></label><div><h3>Saved cover letter '+(i+1)+'</h3><p class="history-meta">'+esc(currentHistory[i].createdAt)+(top?' | '+esc(top.title)+' at '+esc(top.company)+' using '+esc(top.profileLabel||"Selected CV"):'')+'</p></div></div><button class="ghost-button load-history-btn" type="button" data-history-index="'+i+'">Load Letter</button></div></div>';}el.historyList.innerHTML=h;}
function loadHistoryRun(index){if(!currentHistory[index]){return;}current=[];for(var i=0;i<currentHistory[index].results.length;i++){current.push(currentHistory[index].results[i]);}renderSummary();renderResults();}
function findWebsite(name){var key=trim(name);if(!key){return {ok:false,websites:[]};}if(websiteCache[key]){return websiteCache[key];}try{if(window.top&&typeof window.top.lookupOfficialWebsite==="function"){websiteCache[key]=window.top.lookupOfficialWebsite(key);return websiteCache[key];}}catch(e){}websiteCache[key]={ok:false,websites:[]};return websiteCache[key];}
function websiteHtml(info){if(!info||!info.ok||!info.websites||!info.websites.length){return '<p><strong>Website:</strong> No likely official website found.</p>';}var h='<p><strong>Official website:</strong> <a href="'+esc(info.websites[0])+'" target="_blank">'+esc(info.websites[0])+'</a></p>';for(var i=1;i<info.websites.length;i++){h+='<p><strong>Other likely website:</strong> <a href="'+esc(info.websites[i])+'" target="_blank">'+esc(info.websites[i])+'</a></p>';}return h;}
function websiteLine(info){if(!info||!info.ok||!info.websites||!info.websites.length){return "";}return '<p class="job-meta"><strong>Official website:</strong> <a href="'+esc(info.websites[0])+'" target="_blank">'+esc(info.websites[0])+'</a></p>';}
function copyQuietly(text){var ok=false;if(window.navigator&&window.navigator.clipboard&&window.navigator.clipboard.writeText){window.navigator.clipboard.writeText(text);return true;}var a=document.createElement("textarea");a.value=text;a.style.position="absolute";a.style.left="-9999px";document.body.appendChild(a);a.focus();a.select();try{ok=document.execCommand("copy");}catch(e){ok=false;}document.body.removeChild(a);return ok;}
function copyText(text,button,label){var ok=false;if(window.navigator&&window.navigator.clipboard&&window.navigator.clipboard.writeText){window.navigator.clipboard.writeText(text);ok=true;}else{var a=document.createElement("textarea");a.value=text;a.style.position="absolute";a.style.left="-9999px";document.body.appendChild(a);a.focus();a.select();try{ok=document.execCommand("copy");}catch(e){ok=false;}document.body.removeChild(a);}button.innerHTML=ok?"Copied":"Copy failed";setTimeout(function(){button.innerHTML=label;},1500);}
